import csv

questions = [
  {"id":"3841","tipo":"multipla","disciplina":"Matemática","tema":"Análise","subtema":"Derivadas","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"A derivada de f(x) = x³ é:","alternativa_a":"3x²","alternativa_b":"x²","alternativa_c":"3x","alternativa_d":"x⁴/4","alternativa_e":"3","resposta_correta":"a","explicacao":"Regra da potência: se f(x) = xⁿ, então f'(x) = n·xⁿ⁻¹. f(x) = x³ → f'(x) = 3x².","resposta":""},
  {"id":"3842","tipo":"multipla","disciplina":"Física","tema":"Mecânica","subtema":"Momento Angular","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"A Lei de Conservação do Momento Angular explica por que uma patinadora gira mais rápido quando:","alternativa_a":"Recolhe os braços ao corpo (reduz o momento de inércia, aumenta a velocidade angular)","alternativa_b":"Estende os braços para os lados","alternativa_c":"Dobra os joelhos","alternativa_d":"Aumenta a massa corporal","alternativa_e":"Reduz a velocidade linear","resposta_correta":"a","explicacao":"L = I × ω (momento angular = inércia × velocidade angular). Na ausência de torque externo, L é conservado. Ao recolher os braços, I diminui → ω aumenta para manter L = constante. Mesma razão pela qual pulsares giram muito rápido (estrela gigante que colapsa, reduz I).","resposta":""},
  {"id":"3843","tipo":"multipla","disciplina":"Química","tema":"Polímeros","subtema":"Plásticos Biodegradáveis","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Os plásticos biodegradáveis diferem dos convencionais porque:","alternativa_a":"São degradados por microrganismos em tempo relativamente curto","alternativa_b":"São mais resistentes ao calor","alternativa_c":"Derivam exclusivamente do petróleo","alternativa_d":"Não podem ser reciclados","alternativa_e":"São mais poluentes que os convencionais","resposta_correta":"a","explicacao":"Plásticos biodegradáveis (PLA — ácido poliláctico, PHB — polihidroxibutirato) são decompostos por bactérias e fungos. O PLA vem do amido de milho ou cana; o PHB é produzido por bactérias. Vantagem: menor impacto ambiental. Limitação: exigem condições específicas de compostagem para se degradar adequadamente.","resposta":""},
  {"id":"3844","tipo":"multipla","disciplina":"Biologia","tema":"Zoologia","subtema":"Répteis","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Os répteis são vertebrados ectotérmicos. 'Ectotérmico' significa que:","alternativa_a":"Dependem de fontes externas de calor para regular a temperatura corporal","alternativa_b":"Produzem calor internamente pelo metabolismo","alternativa_c":"Mantêm temperatura corporal constante","alternativa_d":"Habitam apenas regiões tropicais","alternativa_e":"Possuem sangue quente","resposta_correta":"a","explicacao":"Ectotérmicos (=poiquilotérmicos, 'sangue frio'): a temperatura corporal varia com o ambiente; dependem de fontes externas de calor (sol, substrato). Répteis, anfíbios, peixes e insetos são ectotérmicos. Aves e mamíferos são endotérmicos (produzem calor internamente).","resposta":""},
  {"id":"3845","tipo":"multipla","disciplina":"História","tema":"Antiguidade","subtema":"Roma Antiga","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A crise da República Romana no século I a.C. culminou na ascensão do Império. Quem foi o primeiro imperador romano?","alternativa_a":"Augusto (Otávio) — 27 a.C.","alternativa_b":"Júlio César","alternativa_c":"Nero","alternativa_d":"Marco Aurélio","alternativa_e":"Constantino","resposta_correta":"a","explicacao":"Augusto (Gaio Otávio Augusto) foi o primeiro imperador romano em 27 a.C., após vencer Marco Antônio e Cleópatra (31 a.C.). Júlio César foi ditador perpétuo (não imperador), assassinado em 44 a.C. O período de Augusto inaugurou a Pax Romana (27 a.C. – 180 d.C.).","resposta":""},
  {"id":"3846","tipo":"multipla","disciplina":"Geografia","tema":"Geopolítica","subtema":"Coreia","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A Coreia do Norte e a Coreia do Sul permanecem tecnicamente em guerra desde:","alternativa_a":"1950 — o armistício de 1953 suspendeu os combates mas não assinou a paz","alternativa_b":"A Segunda Guerra Mundial (1945)","alternativa_c":"1960 — conflito ideológico durante a Guerra Fria","alternativa_d":"1980 — invasão norte-coreana","alternativa_e":"O século XIX, época do colonialismo japonês","resposta_correta":"a","explicacao":"A Guerra da Coreia (1950-1953) envolveu Coreia do Norte (apoiada por China e URSS) e Coreia do Sul (apoiada pelos EUA e ONU). O armistício de julho de 1953 suspendeu os combates, mas nunca houve tratado de paz formal — os dois países permanecem tecnicamente em estado de guerra. A fronteira (paralelo 38) é uma das mais militarizadas do mundo.","resposta":""},
  {"id":"3847","tipo":"multipla","disciplina":"Língua Portuguesa","tema":"Gramática","subtema":"Interjeição","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"'Uau! Que paisagem linda!' — a palavra 'Uau' é classificada como:","alternativa_a":"Interjeição — exprime reação emocional espontânea","alternativa_b":"Advérbio de intensidade","alternativa_c":"Substantivo exclamativo","alternativa_d":"Pronome exclamativo","alternativa_e":"Adjetivo","resposta_correta":"a","explicacao":"Interjeições são palavras ou expressões invariáveis que exprimem reações emocionais espontâneas (surpresa, alegria, dor, chamamento). Não têm função sintática na oração — formam enunciados exclamativos por si sós. Ex.: Ah!, Oh!, Uau!, Ei!, Oxente!","resposta":""},
  {"id":"3848","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Antiga","subtema":"Epicurismo","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Para Epicuro, a felicidade (eudaimonia) consiste em:","alternativa_a":"Ataraxia (tranquilidade da alma) e aponia (ausência de sofrimento físico) — prazer moderado","alternativa_b":"Acumulação de prazeres sensoriais intensos","alternativa_c":"Dedicação exclusiva aos deveres cívicos","alternativa_d":"Contemplação das Ideias platônicas","alternativa_e":"Seguir a razão universal (logos)","resposta_correta":"a","explicacao":"Epicuro (Jardim) não prega o hedonismo grosseiro: o prazer que busca é catastático (estável) — ataraxia (ausência de perturbação mental) e aponia (ausência de dor). Evitar medos (da morte, dos deuses) e cultivar amizade. 'A morte nada é para nós — quando ela está, nós não estamos.'","resposta":""},
  {"id":"3849","tipo":"multipla","disciplina":"Sociologia","tema":"Política","subtema":"Democracia Participativa","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O orçamento participativo é um mecanismo de democracia participativa no qual:","alternativa_a":"A população decide diretamente a destinação de parte do orçamento público municipal","alternativa_b":"O governo decide o orçamento sem consulta popular","alternativa_c":"Empresas privadas gerem recursos públicos","alternativa_d":"Partidos políticos dividem o orçamento entre si","alternativa_e":"O FMI define as prioridades de gasto público","resposta_correta":"a","explicacao":"O orçamento participativo (OP) foi implementado em Porto Alegre em 1989 (governo Olívio Dutra/PT) e expandido para centenas de cidades no Brasil e no mundo. Cidadãos participam em assembleias para definir prioridades de investimento público (saúde, educação, infraestrutura). Exemplo de democracia direta combinada com representativa.","resposta":""},
  {"id":"3850","tipo":"multipla","disciplina":"Matemática","tema":"Funções","subtema":"Análise de Gráficos","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Uma função f é injetora (injetiva) se:","alternativa_a":"Elementos distintos do domínio têm imagens distintas (f(x₁) ≠ f(x₂) se x₁ ≠ x₂)","alternativa_b":"Todo elemento do contradomínio tem pelo menos uma pré-imagem","alternativa_c":"Domínio e imagem são conjuntos iguais","alternativa_d":"A função tem inversa em todo o domínio","alternativa_e":"A função é crescente em todo o domínio","resposta_correta":"a","explicacao":"Função injetora (ou 1-1): elementos distintos do domínio → imagens distintas. Função sobrejetora: todo elemento do contradomínio é imagem de algum elemento do domínio. Função bijetora: injetora + sobrejetora → tem inversa.","resposta":""},
  {"id":"3851","tipo":"multipla","disciplina":"Física","tema":"Óptica","subtema":"Dispersão da Luz","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O arco-íris é formado pela:","alternativa_a":"Dispersão e reflexão interna da luz solar em gotículas de água","alternativa_b":"Emissão de luz pelas nuvens","alternativa_c":"Interferência construtiva da luz do sol","alternativa_d":"Difração da luz nas bordas das nuvens","alternativa_e":"Polarização da luz solar pela atmosfera","resposta_correta":"a","explicacao":"A luz solar (branca) ao entrar em uma gota de água sofre: refração (entra e sai da gota), reflexão interna total (no interior da gota) e dispersão — diferentes comprimentos de onda (cores) são refratados em ângulos ligeiramente diferentes, separando o branco nas cores do espectro visível (ROVAZUL).","resposta":""},
  {"id":"3852","tipo":"multipla","disciplina":"Química","tema":"Bioquímica","subtema":"Fermentação Lática","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A fermentação lática ocorre em células musculares quando há falta de oxigênio e produz:","alternativa_a":"Ácido láctico (lactato) + energia (2 ATP)","alternativa_b":"Etanol + CO₂","alternativa_c":"Glicose + O₂","alternativa_d":"Piruvato + NADH","alternativa_e":"CO₂ + H₂O","resposta_correta":"a","explicacao":"Fermentação lática: piruvato + NADH → lactato + NAD⁺. Ocorre em células musculares sob esforço intenso (sem O₂ suficiente) e em bactérias lácticas. Produz apenas 2 ATP (via glicólise). O acúmulo de lactato no músculo causa a dor muscular após exercício intenso. Também usada na produção de iogurte e queijo.","resposta":""},
  {"id":"3853","tipo":"multipla","disciplina":"Biologia","tema":"Evolução","subtema":"Especiação","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A especiação alopátrica ocorre quando:","alternativa_a":"Populações de uma mesma espécie são isoladas geograficamente e evoluem separadamente","alternativa_b":"Duas espécies diferentes se fundem em uma","alternativa_c":"Espécies evoluem no mesmo território sem isolamento geográfico","alternativa_d":"Mutações idênticas ocorrem em populações diferentes","alternativa_e":"Uma espécie migra para um novo habitat sem se isolar","resposta_correta":"a","explicacao":"Especiação alopátrica: isolamento geográfico (montanha, oceano, deserto) separa populações → pressões seletivas diferentes → acúmulo de diferenças genéticas → incapacidade de cruzamento → nova espécie. Especiação simpátrica: ocorre no mesmo espaço geográfico (poliploidia em plantas, seleção disruptiva).","resposta":""},
  {"id":"3854","tipo":"multipla","disciplina":"História","tema":"Brasil","subtema":"Operação Lava Jato","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A Operação Lava Jato (2014-2021) foi uma investigação sobre:","alternativa_a":"Corrupção na Petrobras: esquema de desvio de recursos por empreiteiras e pagamento de propinas a políticos","alternativa_b":"Crimes ambientais na Amazônia","alternativa_c":"Fraudes eleitorais nas eleições de 2014","alternativa_d":"Lavagem de dinheiro no setor agrário","alternativa_e":"Tráfico de armas nas fronteiras","resposta_correta":"a","explicacao":"A Lava Jato (iniciada em Curitiba pelo juiz Sérgio Moro) investigou um esquema de corrupção na Petrobras: empreiteiras pagavam propinas a funcionários e políticos em troca de contratos superfaturados. Resultou em condenações de empresários e políticos (incluindo líderes de PT, PSDB, MDB), destruição de empreiteiras e debate sobre limites do poder judiciário.","resposta":""},
  {"id":"3855","tipo":"multipla","disciplina":"Língua Portuguesa","tema":"Literatura","subtema":"João Guimarães Rosa","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"'Grande Sertão: Veredas' (1956), de João Guimarães Rosa, é considerado o maior romance da literatura brasileira. Sua principal inovação linguística é:","alternativa_a":"A reinvenção da língua portuguesa com neologismos, arcaísmos e fusão do falar sertanejo com o erudito","alternativa_b":"A adoção da linguagem coloquial urbana carioca","alternativa_c":"O uso exclusivo do inglês em citações","alternativa_d":"A narrativa em segunda pessoa do plural","alternativa_e":"A reprodução literal do falar nordestino sem intervenção literária","resposta_correta":"a","explicacao":"Guimarães Rosa (mineiro, médico e diplomata) recriou a língua portuguesa em 'Grande Sertão: Veredas': mistura do falar sertanejo de Minas, arcaísmos do português colonial, neologismos, onomatopeias e construções sintáticas únicas. O narrador Riobaldo conta sua vida de jagunço ao mesmo tempo que faz uma metafísica popular sobre Deus, o diabo e o amor. Considerado o 'Ulisses' brasileiro.","resposta":""},
  {"id":"3856","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia do Direito","subtema":"Direito Natural","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O jusnaturalismo (direito natural) afirma que:","alternativa_a":"Existem direitos universais e imutáveis que precedem e limitam o direito positivo (leis criadas pelo Estado)","alternativa_b":"Só o direito criado pelo Estado é legítimo","alternativa_c":"Os direitos variam completamente de cultura para cultura","alternativa_d":"A lei é expressão da vontade do mais forte","alternativa_e":"Os direitos são determinados exclusivamente pelo contrato social vigente","resposta_correta":"a","explicacao":"Jusnaturalismo: há uma ordem jurídica natural (baseada na razão, na natureza humana ou na divindade) que é universal, imutável e superior ao direito positivo. Serve de critério para julgar a justiça das leis. Contrasta com o positivismo jurídico (Kelsen): só o direito positivo (criado pelo Estado) é direito. Os Direitos Humanos têm fundamentação jusnaturalista.","resposta":""},
  {"id":"3857","tipo":"multipla","disciplina":"Matemática","tema":"Geometria Plana","subtema":"Trapézio","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A área de um trapézio com bases B = 10 cm e b = 6 cm e altura h = 4 cm é:","alternativa_a":"32 cm²","alternativa_b":"24 cm²","alternativa_c":"40 cm²","alternativa_d":"60 cm²","alternativa_e":"16 cm²","resposta_correta":"a","explicacao":"A = (B + b) × h / 2 = (10 + 6) × 4 / 2 = 16 × 2 = 32 cm².","resposta":""},
  {"id":"3858","tipo":"multipla","disciplina":"Química","tema":"Reações","subtema":"Velocidade de Reação","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Aumentar a temperatura de uma reação química geralmente:","alternativa_a":"Aumenta a velocidade da reação (mais colisões efetivas entre moléculas)","alternativa_b":"Diminui a velocidade da reação","alternativa_c":"Não afeta a velocidade da reação","alternativa_d":"Diminui a concentração dos reagentes","alternativa_e":"Altera o produto da reação","resposta_correta":"a","explicacao":"Temperatura aumenta a energia cinética das moléculas → mais colisões por unidade de tempo → maior fração de moléculas com energia ≥ energia de ativação → velocidade aumenta. Regra de Van't Hoff: a cada 10°C de aumento, a velocidade aproximadamente dobra.","resposta":""},
  {"id":"3859","tipo":"multipla","disciplina":"Biologia","tema":"Saúde","subtema":"Câncer","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O câncer é causado por:","alternativa_a":"Mutações em genes que controlam o ciclo celular (proto-oncogenes e genes supressores de tumor)","alternativa_b":"Vírus que substituem o DNA celular","alternativa_c":"Deficiência nutricional de vitaminas","alternativa_d":"Infecção bacteriana crônica em qualquer tecido","alternativa_e":"Exposição a campos eletromagnéticos de baixa frequência","resposta_correta":"a","explicacao":"Câncer = crescimento celular descontrolado. Causas: mutações em proto-oncogenes (genes que estimulam a divisão → viram oncogenes quando mutados) e em genes supressores de tumor (ex.: TP53, gene do 'guardião do genoma'). Fatores: tabagismo, radiação UV, agentes químicos, vírus (HPV, HBV), predisposição genética.","resposta":""},
  {"id":"3860","tipo":"multipla","disciplina":"Geografia","tema":"Geopolítica","subtema":"Protecionismo","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O protecionismo econômico refere-se a políticas que:","alternativa_a":"Protegem a indústria nacional da concorrência estrangeira por meio de tarifas, cotas e subsídios","alternativa_b":"Abrem completamente a economia ao comércio internacional","alternativa_c":"Promovem a livre circulação de trabalhadores entre países","alternativa_d":"Privatizam empresas estatais","alternativa_e":"Incentivam o investimento estrangeiro direto","resposta_correta":"a","explicacao":"Protecionismo: conjunto de medidas que restringem importações e favorecem produtores nacionais: tarifas alfandegárias (impostos sobre importações), cotas (limite de volume importado), subsídios a exportadores, barreiras técnicas. Debates: protege empregos e setores estratégicos vs. reduz a eficiência e gera retaliações comerciais.","resposta":""},
  {"id":"4551","tipo":"dissertativa","disciplina":"Matemática","tema":"Probabilidade","subtema":"Teorema de Bayes","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Um teste diagnóstico tem sensibilidade de 95% e especificidade de 90%. Se a prevalência da doença é 1%, qual é a probabilidade de uma pessoa ter a doença dado que testou positivo? (Use Teorema de Bayes)","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"P(D) = 0,01; P(D̄) = 0,99. Sensibilidade P(+|D) = 0,95; especificidade P(−|D̄) = 0,90 → P(+|D̄) = 0,10. P(+) = P(+|D)×P(D) + P(+|D̄)×P(D̄) = 0,95×0,01 + 0,10×0,99 = 0,0095 + 0,099 = 0,1085. P(D|+) = P(+|D)×P(D)/P(+) = 0,0095/0,1085 ≈ 8,76%. Apesar do teste ser bom, com prevalência de apenas 1%, a maioria dos positivos são falsos positivos — ilustra a importância da prevalência.","resposta":"≈ 8,76% — a baixa prevalência faz que a maioria dos testes positivos sejam falsos positivos"},
  {"id":"4552","tipo":"dissertativa","disciplina":"Física","tema":"Física Moderna","subtema":"Dualidade Onda-Partícula","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Explique o conceito de dualidade onda-partícula e o experimento da dupla fenda.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Dualidade onda-partícula: partículas como elétrons e fótons comportam-se como ondas em alguns experimentos e como partículas em outros. No experimento da dupla fenda (Young com elétrons): elétrons individuais passam pelas duas fendas e produzem um padrão de interferência (como ondas) na tela — impossível se fossem apenas partículas. Quando se instala um detector para observar por qual fenda o elétron passa, o padrão de interferência desaparece — a observação colapsa a função de onda, e o elétron comporta-se como partícula. Isso revela que a medição afeta o sistema quântico (princípio de Heisenberg + interpretação de Copenhague).","resposta":"Dualidade: elétrons são onda sem observação (interferência) e partícula ao serem observados — o ato de medir colapsa a função de onda"},
  {"id":"4553","tipo":"dissertativa","disciplina":"Química","tema":"Orgânica","subtema":"Síntese Orgânica","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Descreva a síntese do ácido acetilsalicílico (aspirina) a partir do ácido salicílico.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"A aspirina (ácido acetilsalicílico) é sintetizada por acetilação do ácido salicílico: Ácido salicílico + anidrido acético → ácido acetilsalicílico + ácido acético. A reação ocorre em meio ácido (algumas gotas de H₂SO₄ como catalisador) com aquecimento suave. O grupo –OH fenólico do salicílico é substituído pelo grupo acetila (–OCOCH₃), tornando o composto menos irritante para o estômago. A síntese é simples, de alta pureza e de custo baixo — primeira síntese farmacêutica industrial (Felix Hoffmann, Bayer, 1897).","resposta":"Ácido salicílico + anidrido acético → aspirina + ácido acético (acetilação do grupo OH fenólico em meio ácido)"},
  {"id":"4554","tipo":"dissertativa","disciplina":"Biologia","tema":"Biologia Evolutiva","subtema":"Coevolução","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que é coevolução? Cite dois exemplos de coevolução na natureza.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Coevolução: processo pelo qual duas (ou mais) espécies exercem pressões seletivas mútuas ao longo do tempo, evoluindo de forma interdependente. Exemplos: (1) Flores e polinizadores — a flor de orquídea da espécie Angraecum sesquipedale de Madagascar tem néctar no fundo de um tubo de 30 cm. Darwin previu que deveria existir um inseto com espirotromba de 30 cm — confirmado em 1903 com o descobrimento da esfinge Xanthopan morganii. A flor evoluiu o tubo longo; a mariposa, a probóscide comprida. (2) Predador-presa: o coelho evoluiu velocidade maior; a raposa, que pressiona o coelho, também evoluiu mais velocidade. 'Corrida armamentista' evolutiva.","resposta":"Coevolução: espécies evoluem em resposta uma à outra. Exemplos: orquídea e esfinge (probóscide comprida); predador e presa (corrida armamentista evolutiva)"},
  {"id":"4555","tipo":"dissertativa","disciplina":"História","tema":"Contemporânea","subtema":"Direitos Humanos no Brasil","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Quais são os principais instrumentos internacionais de proteção dos direitos humanos e como o Brasil se inseriu nesse sistema?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Instrumentos internacionais: (1) Declaração Universal dos Direitos Humanos (ONU, 1948) — não vinculante mas moral; (2) Pacto Internacional dos Direitos Civis e Políticos (1966); (3) Pacto Internacional dos Direitos Econômicos, Sociais e Culturais (1966); (4) Convenção Americana sobre Direitos Humanos — Pacto de San José da Costa Rica (1969); (5) Convenção contra a Tortura (1984). O Brasil aderiu à maioria após a redemocratização (1988): ratificou os tratados internacionais de DH, criou a Secretaria de Direitos Humanos, e a CF/88 incorporou direitos fundamentais extensos. O Brasil reconhece a jurisdição da Corte Interamericana de DH (desde 1998).","resposta":"DUDH (1948), Pactos da ONU (1966), Pacto de San José (1969). Brasil aderiu após 1988, reconhece a Corte Interamericana e incorporou DH na Constituição"},
  {"id":"4556","tipo":"dissertativa","disciplina":"Língua Portuguesa","tema":"Gramática","subtema":"Sintaxe do Período Composto","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Analise as relações sintáticas em: 'Embora estivesse cansado, ele continuou estudando, pois queria passar no vestibular.'","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Período composto por subordinação e coordenação. Orações: (1) 'Embora estivesse cansado' — subordinada adverbial concessiva (contradição admitida; conjunção 'embora' + subjuntivo). (2) 'ele continuou estudando' — oração principal (oração principal do período, independente). (3) 'pois queria passar no vestibular' — subordinada adverbial causal (explica a causa de 'continuou estudando'; conjunção 'pois'). Relação: concessão (1) + fato principal (2) + causa (3).","resposta":"'Embora...' = subordinada adverbial concessiva; 'ele continuou...' = oração principal; 'pois...' = subordinada adverbial causal"},
  {"id":"4557","tipo":"dissertativa","disciplina":"Filosofia","tema":"Filosofia da Linguagem","subtema":"Atos de Fala","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Explique a teoria dos atos de fala de J.L. Austin e a distinção entre atos locucionários, ilocucionários e perlocucionários.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Austin ('How to Do Things with Words', 1962) propôs que a linguagem não apenas descreve a realidade, mas realiza ações. Três dimensões de um ato de fala: (1) Ato locucionário: o ato de proferir sons com significado ('Feche a porta'); (2) Ato ilocucionário: a força da fala — o que se está fazendo ao dizer (ordem, pedido, promessa, aviso, declaração): 'Feche a porta' pode ser ordem ou pedido; (3) Ato perlocucionário: o efeito causado no ouvinte pela fala (a pessoa fecha a porta, fica com medo, etc.). Austin distinguiu performativos (que realizam ação: 'Eu te declaro casados') de constatativos (descritivos).","resposta":"Locucionário: o que se diz. Ilocucionário: o que se faz ao dizer (ordem, promessa). Perlocucionário: o efeito no ouvinte — Austin"},
  {"id":"4558","tipo":"dissertativa","disciplina":"Sociologia","tema":"Saúde Mental","subtema":"Medicalização","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que é medicalização da vida? Discuta criticamente seu impacto na sociedade.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Medicalização da vida (Foucault, Conrad): processo pelo qual comportamentos e estados da vida cotidiana são redefinidos como problemas médicos que requerem tratamento. Ex.: tristeza → depressão → antidepressivo; timidez → fobia social → medicação; criança agitada → TDAH → Ritalina. Impactos críticos: (1) Amplia o controle biomédico sobre a vida; (2) Reduz questões sociais (pobreza, violência, pressão escolar) a diagnósticos individuais; (3) Beneficia a indústria farmacêutica; (4) Pode aliviar sofrimento genuíno quando bem indicada. O desafio é distinguir sofrimento que requer tratamento do mal-estar social que exige transformação estrutural.","resposta":"Medicalização: comportamentos cotidianos redefindos como doenças. Crítica: responsabiliza indivíduos por problemas sociais e beneficia a indústria farmacêutica"},
  {"id":"4559","tipo":"dissertativa","disciplina":"Geografia","tema":"Geopolítica","subtema":"África","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Por que a África subsaariana concentra os piores indicadores de desenvolvimento humano do mundo?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"A concentração de baixo IDH na África subsaariana resulta de múltiplos fatores históricos e estruturais: (1) Colonialismo: exploração dos recursos, fronteiras artificiais que ignoraram etnias, ausência de desenvolvimento local; (2) Dívida externa e ajustes estruturais do FMI (décadas de 1980-90) que cortaram gastos em saúde e educação; (3) Conflitos armados contínuos que destroem infraestrutura e deslocam populações; (4) Doenças endêmicas (malária, HIV/AIDS, tuberculose) que reduzem força de trabalho; (5) Dependência de commodities com termos de troca desfavoráveis; (6) Corrupção e governança fraca. A region tem enormes recursos naturais mas enfrenta a 'maldição dos recursos'.","resposta":"Colonialismo, conflitos, doenças, dependência de commodities, ajustes do FMI e governança fraca perpetuam o baixo desenvolvimento humano na África subsaariana"},
  {"id":"4560","tipo":"dissertativa","disciplina":"Matemática","tema":"Cálculo","subtema":"Integral Definida","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Calcule a integral definida ∫₀² x² dx e interprete geometricamente o resultado.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"∫x² dx = x³/3 + C (antiderivada). Integral definida: [x³/3]₀² = (2³/3) − (0³/3) = 8/3 − 0 = 8/3 ≈ 2,67. Interpretação geométrica: a integral definida ∫₀² x² dx representa a área sob a curva y = x² entre x = 0 e x = 2 — a área da região delimitada pela parábola, o eixo x e as retas x = 0 e x = 2, que é igual a 8/3 unidades de área.","resposta":"∫₀² x² dx = 8/3; geometricamente é a área sob a parábola y = x² entre x = 0 e x = 2"},
]

